    pub fn admit(&self, _envelope: RunEnvelope, _memory: &omega_myelin::MemoryGraph) -> RunStatus {
        RunStatus::Admitted
    }
}
```

- **AEON goal binding ignores the provided contract** (sets a hardcoded default instead):

```59:70:/home/mega/Chyren/omega_workspace/workspace/OmegA-Next/omega-aeon/src/lib.rs
pub fn bind_goal(&mut self, task_id: &str, contract: GoalContract) -> Result<(), String> {
    // ...
    task.goal_contract = Some(GoalContract { objective: "default".into(), success_criteria: "none".into(), constraints: vec![], claim_budget: ClaimBudget { total: 0.0, remaining: 0.0 } });
    task.stage = TaskStage::Planned;
    // ...
    Ok(())
